DO $kim384_rls$ BEGIN ALTER TABLE public.saved_games ENABLE ROW LEVEL SECURITY; ALTER TABLE public.saved_game_attendances ENABLE ROW LEVEL SECURITY; CREATE POLICY "saved_games_select" ON public.saved_games FOR SELECT TO authenticated USING (((SELECT auth.uid()) = user_id) OR (SELECT internal.is_admin())); CREATE POLICY "saved_game_attendances_select" ON public.saved_game_attendances FOR SELECT TO authenticated USING (EXISTS (SELECT 1 FROM public.saved_games WHERE saved_games.id = saved_game_attendances.saved_game_id AND (saved_games.user_id = (SELECT auth.uid()) OR (SELECT internal.is_admin())))); GRANT SELECT ON TABLE public.saved_games, public.saved_game_attendances TO authenticated; GRANT ALL ON TABLE public.saved_games, public.saved_game_attendances TO service_role; REVOKE EXECUTE ON FUNCTION public.validate_saved_game() FROM PUBLIC, anon, authenticated; REVOKE EXECUTE ON FUNCTION public.increment_saved_game_attendance() FROM PUBLIC, anon, authenticated; REVOKE EXECUTE ON FUNCTION public.cancel_saved_games_for_event_block() FROM PUBLIC, anon, authenticated; END $kim384_rls$;
